/**
 * perplexityClient.js
 * Shared Perplexity API client for all CPC sports research pipelines.
 *
 * Contract rules:
 *  - All prompts must request JSON-only output.
 *  - Unknown / unavailable values MUST be returned as null (never invented).
 *  - If PERPLEXITY_API_KEY is absent or the API fails, safe fallback is returned.
 *  - No market price data is ever included in research prompts.
 *  - No betting/wagering language is ever generated by this client.
 */

'use strict';

const https = require('https');
const { SPORT_TOKEN_BUDGETS } = require('./sportTokenBudgets');

// ─── Constants ───────────────────────────────────────────────────────────────

const PERPLEXITY_API_URL = 'api.perplexity.ai';
const PERPLEXITY_API_PATH = '/chat/completions';
const DEFAULT_MODEL = 'sonar';
const MAX_RETRIES = 2;
const RETRY_DELAY_MS = 1200;

/** Words that must never appear in any research prompt sent by this client. */
const BANNED_PROMPT_TERMS = [
  'bet', 'betting', 'wager', 'sportsbook', 'odds', 'moneyline', 'prop',
  'pick', 'lean', 'lock', 'fade', 'edge', 'trade', 'buy', 'sell',
  'bankroll', 'stake', 'unit', 'market price', 'bid', 'ask',
  'open interest', 'volume', 'liquidity', 'NOT IN SCORE', 'display-only',
];

// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Returns true if the prompt contains any banned term.
 * @param {string} prompt
 * @returns {{ safe: boolean, violations: string[] }}
 */
function auditPrompt(prompt) {
  const lower = prompt.toLowerCase();
  const violations = BANNED_PROMPT_TERMS.filter(t => lower.includes(t.toLowerCase()));
  return { safe: violations.length === 0, violations };
}

/**
 * Delay helper.
 * @param {number} ms
 */
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Makes a raw HTTPS POST to the Perplexity API.
 * @param {string} apiKey
 * @param {object} body
 * @returns {Promise<object>}
 */
function postPerplexity(apiKey, body) {
  return new Promise((resolve, reject) => {
    const payload = JSON.stringify(body);
    const options = {
      hostname: PERPLEXITY_API_URL,
      path: PERPLEXITY_API_PATH,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`,
        'Content-Length': Buffer.byteLength(payload),
      },
    };
    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', chunk => { data += chunk; });
      res.on('end', () => {
        try {
          resolve({ status: res.statusCode, body: JSON.parse(data) });
        } catch {
          resolve({ status: res.statusCode, body: { raw: data } });
        }
      });
    });
    req.on('error', reject);
    req.write(payload);
    req.end();
  });
}

// ─── Safe Fallback ────────────────────────────────────────────────────────────

/**
 * Returns a structured safe fallback when Perplexity is unavailable or has no key.
 * All research fields are null. Callers must treat this as a blocked research result.
 *
 * @param {string} sport
 * @param {string} reason
 * @returns {object}
 */
function buildSafeFallback(sport, reason) {
  return {
    _meta: {
      provider: 'perplexity',
      model: null,
      sport,
      status: 'unavailable',
      reason,
      fetched_utc: null,
      cost_usd: null,
      citations: [],
      parse_status: 'fallback',
      missing_fields: ['all'],
    },
    research: null,
  };
}

// ─── Core Client ──────────────────────────────────────────────────────────────

/**
 * Main Perplexity research call.
 *
 * @param {object} opts
 * @param {string} opts.sport          — e.g. 'mlb', 'worldcup', 'ufc', 'nascar'
 * @param {string} opts.systemPrompt   — Must request JSON-only output, null for unknowns
 * @param {string} opts.userPrompt     — Event-specific research query
 * @param {string} [opts.model]        — Override model; defaults to DEFAULT_MODEL
 * @param {boolean} [opts.dryRun]      — If true, skips API call and returns safe fallback
 * @returns {Promise<object>}          — { _meta, research } or safe fallback
 */
async function callPerplexity(opts) {
  const {
    sport = 'unknown',
    systemPrompt = '',
    userPrompt = '',
    model = DEFAULT_MODEL,
    dryRun = false,
  } = opts;

  // ── Prompt audit ──
  const sysAudit = auditPrompt(systemPrompt);
  const userAudit = auditPrompt(userPrompt);
  if (!sysAudit.safe || !userAudit.safe) {
    const violations = [...new Set([...sysAudit.violations, ...userAudit.violations])];
    console.error('[perplexityClient] BLOCKED — prompt contains banned terms:', violations);
    return buildSafeFallback(sport, `prompt_audit_fail:${violations.join(',')}`);
  }

  // ── No-key safe path ──
  const apiKey = process.env.PERPLEXITY_API_KEY || '';
  if (!apiKey || dryRun) {
    const reason = dryRun ? 'dry_run' : 'no_api_key';
    console.warn(`[perplexityClient] Safe fallback — ${reason} for sport=${sport}`);
    return buildSafeFallback(sport, reason);
  }

  // ── Token budget ──
  const budget = SPORT_TOKEN_BUDGETS[sport] || SPORT_TOKEN_BUDGETS.default;

  const body = {
    model,
    max_tokens: budget.max_tokens,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt },
    ],
    return_citations: true,
    return_images: false,
    search_recency_filter: budget.recency_filter || 'day',
  };

  // ── Retry loop ──
  let lastError = null;
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    if (attempt > 0) await sleep(RETRY_DELAY_MS * attempt);
    try {
      const { status, body: respBody } = await postPerplexity(apiKey, body);

      if (status !== 200) {
        lastError = `http_${status}`;
        console.warn(`[perplexityClient] Attempt ${attempt + 1} failed — status ${status}`);
        continue;
      }

      const content = respBody?.choices?.[0]?.message?.content || '';
      const citations = respBody?.citations || [];
      const usage = respBody?.usage || {};

      let parsed = null;
      let parseStatus = 'ok';
      const missingFields = [];

      try {
        // Strip markdown code fences if present
        const cleaned = content.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();
        parsed = JSON.parse(cleaned);
      } catch {
        parseStatus = 'parse_error';
        console.error('[perplexityClient] JSON parse failed. Raw content stored in _meta.');
      }

      // Collect top-level null fields as missing
      if (parsed && typeof parsed === 'object') {
        for (const [k, v] of Object.entries(parsed)) {
          if (v === null || v === undefined) missingFields.push(k);
        }
      }

      return {
        _meta: {
          provider: 'perplexity',
          model,
          sport,
          status: 'ok',
          reason: null,
          fetched_utc: new Date().toISOString(),
          cost_usd: usage.total_tokens ? (usage.total_tokens * 0.000001).toFixed(6) : null,
          citations,
          parse_status: parseStatus,
          missing_fields: missingFields,
          raw_content: parseStatus === 'parse_error' ? content : undefined,
        },
        research: parsed,
      };
    } catch (err) {
      lastError = err.message;
      console.error(`[perplexityClient] Attempt ${attempt + 1} threw:`, err.message);
    }
  }

  // ── All retries exhausted ──
  return buildSafeFallback(sport, `api_failure:${lastError}`);
}

// ─── Exports ──────────────────────────────────────────────────────────────────

module.exports = {
  callPerplexity,
  auditPrompt,
  buildSafeFallback,
  BANNED_PROMPT_TERMS,
};
